#include <bits/stdc++.h>
#define l first
#define r second
using namespace std;
typedef pair<int,int> pii;

const int N=4e5+10;

struct Edge{
    int u,v;
}edge[N*2];

struct Que{
    int l,r,x,id;
}ask[N*2];

int n,m,q,f[N],ch1[N*2][2],ch2[N*2][2],v1[N*2],v2[N*2],w[N],cnt,dfn[N],num,b1[N*2][20],b2[N*2][20],tot,c[N];
int ans[N];
pii seg1[N*2],seg2[N*2];

bool cmp1(Edge x,Edge y){
    return min(x.u,x.v)>min(y.u,y.v);
}

bool cmp2(Edge x,Edge y){
    return max(x.u,x.v)<max(y.u,y.v);
}

void dfs1(int x){
    for(int i=1;i<20;i++)
        b1[x][i]=b1[b1[x][i-1]][i-1];
    if(x<=n){
        w[++cnt]=x;
        seg1[x]=make_pair(cnt,cnt);
        return;
    }
    dfs1(ch1[x][0]);
    dfs1(ch1[x][1]);
    seg1[x]=make_pair(seg1[ch1[x][0]].l,seg1[ch1[x][1]].r);
}

void dfs2(int x){
    for(int i=1;i<20;i++)
        b2[x][i]=b2[b2[x][i-1]][i-1];
    if(x<=n){
        dfn[x]=++num;
        seg2[x]=make_pair(num,num);
        return;
    }
    dfs2(ch2[x][0]);
    dfs2(ch2[x][1]);
    seg2[x]=make_pair(seg2[ch2[x][0]].l,seg2[ch2[x][1]].r);
}

int father(int x){
	return f[x]==x?x:f[x]=father(f[x]);
} 

bool cmp(Que x,Que y){
    return x.x<y.x;
}

void add(int x){
    for(;x<=n;x+=(x&(-x)))
        c[x]++;
}

int Ask(int x){
    int res=0;
    for(;x;x-=(x&(-x)))
        res+=c[x];
    return res;
}

int main(){
    scanf("%d%d%d",&n,&m,&q);
    for(int i=1;i<=m;i++){
        scanf("%d%d",&edge[i].u,&edge[i].v);
        edge[i].u++,edge[i].v++;
    }
    sort(edge+1,edge+m+1,cmp1);
    for(int i=1;i<2*n;i++)
        f[i]=i;
    int now=n;
    for(int i=1;i<=m && now<2*n-1;i++){
        int fu=father(edge[i].u),fv=father(edge[i].v);
        if(fu!=fv){
            now++;
            ch1[now][0]=fu;
            ch1[now][1]=fv;
            f[fu]=f[fv]=now;
            b1[fu][0]=b1[fv][0]=now;
            v1[now]=min(edge[i].u,edge[i].v);
        }
    }
    dfs1(now);
//    for(int i=1;i<=n;i++)
//    	printf("%d ",w[i]);
//    puts("");
    sort(edge+1,edge+m+1,cmp2);
    for(int i=1;i<2*n;i++)
        f[i]=i;
    now=n;
    for(int i=1;i<=m && now<2*n-1;i++){
        int fu=father(edge[i].u),fv=father(edge[i].v);
        if(fu!=fv){
//        	printf("add: %d %d\n",edge[i].u,edge[i].v);
            now++;
            ch2[now][0]=fu;
            ch2[now][1]=fv;
            f[fu]=f[fv]=now;
            b2[fu][0]=b2[fv][0]=now;
            v2[now]=max(edge[i].u,edge[i].v);
        }
    }
    dfs2(now);
//    for(int i=1;i<=n;i++)
//    	printf("%d ",dfn[i]);
//    puts("");
    for(int i=1;i<=q;i++){
        int s,e,l,r;
        scanf("%d%d%d%d",&s,&e,&l,&r);
        s++,e++,l++,r++;
        if(s<l || e>r)
            ans[i]=0;
        else{
            int x=s,y=e;
            for(int i=19;i>=0;i--)
                if(b1[x][i] && v1[b1[x][i]]>=l)
                    x=b1[x][i];
            for(int i=19;i>=0;i--)
                if(b2[y][i] && v2[b2[y][i]]<=r)
                    y=b2[y][i];
//            printf("ask: %d %d %d %d\n",seg2[y].l,seg2[y].r,seg1[x].l,seg1[x].r);
            ask[++tot]={seg2[y].l,seg2[y].r,seg1[x].r,i};
            ask[++tot]={seg2[y].l,seg2[y].r,seg1[x].l-1,-i};
        }
    }
    sort(ask+1,ask+tot+1,cmp);
    for(int i=1,j=1;i<=tot;i++){
//    	printf("%d\n",i);
        while(j<=ask[i].x){
//			printf("%d %d\n",j,dfn[w[j]]);
            add(dfn[w[j]]),j++;
        }
//        printf("%d %d %d %d %d\n",ask[i].l,ask[i].r,ask[i].x,ask[i].id,Ask(ask[i].r)-Ask(ask[i].l-1));
        if(ask[i].id>0){
//            printf("%d %d\n",ans[ask[i].id],Ask(ask[i].r)-Ask(ask[i].l-1));
//			puts("TP1");
            ans[ask[i].id]+=Ask(ask[i].r)-Ask(ask[i].l-1);
//            printf("%d %d\n",ans[ask[i].id],Ask(ask[i].r)-Ask(ask[i].l-1));
        }else{
//            printf("%d %d\n",ans[-ask[i].id],Ask(ask[i].r)-Ask(ask[i].l-1));
//			puts("TP2");
            ans[-ask[i].id]-=Ask(ask[i].r)-Ask(ask[i].l-1);
//            printf("%d %d\n",ans[-ask[i].id],Ask(ask[i].r)-Ask(ask[i].l-1));
        }
    }
    for(int i=1;i<=q;i++)
        printf("%d\n",ans[i]>0);
    return 0;
}
